func TestSkillInstallDryRunPrintsInstallerCommand(t *testing.T) {
	var flags rootFlags
	cmd := newRootCmd(&flags)
	var out bytes.Buffer
	cmd.SetOut(&out)
	cmd.SetErr(&out)
	cmd.SetArgs([]string{"skill", "install", "--dry-run"})

	if err := cmd.Execute(); err != nil {
		t.Fatalf("Execute() error = %v, want nil", err)
	}
	want := "would run: npx -y @mvanhorn/printing-press install erank --skill-only --agent claude-code --agent codex"
	if !strings.Contains(out.String(), want) {
		t.Fatalf("output = %q, want %q", out.String(), want)
	}
}

func TestSkillInstallRunsPrintingPressInstaller(t *testing.T) {
	oldRunner := runSkillInstallCommand
	t.Cleanup(func() { runSkillInstallCommand = oldRunner })

	var gotName string
	var gotArgs []string
	runSkillInstallCommand = func(ctx context.Context, stdout io.Writer, stderr io.Writer, name string, args ...string) error {
		gotName = name
		gotArgs = append([]string{}, args...)
		_, _ = stdout.Write([]byte("installer output\n"))
		return nil
	}

	var flags rootFlags
	cmd := newRootCmd(&flags)
	var out bytes.Buffer
	var errOut bytes.Buffer
	cmd.SetOut(&out)
	cmd.SetErr(&errOut)
	cmd.SetArgs([]string{"skill", "install", "--json"})

	if err := cmd.Execute(); err != nil {
		t.Fatalf("Execute() error = %v, want nil", err)
	}
	if gotName != "npx" {
		t.Fatalf("runner name = %q, want npx", gotName)
	}
	wantArgs := "-y @mvanhorn/printing-press install erank --skill-only --agent claude-code --agent codex"
	if strings.Join(gotArgs, " ") != wantArgs {
		t.Fatalf("runner args = %q, want %q", strings.Join(gotArgs, " "), wantArgs)
	}
	if !strings.Contains(out.String(), `"status": "installed"`) {
		t.Fatalf("stdout = %q, want JSON install status", out.String())
	}
	if strings.Contains(out.String(), "installer output") {
		t.Fatalf("stdout = %q, installer output must stay off stdout", out.String())
	}
	if !strings.Contains(errOut.String(), "installer output") {
		t.Fatalf("stderr = %q, want installer output", errOut.String())
	}
}
